parameters.jsCode:
// Extract traceId from execution metadata or workflow context
const errorData = $input.item.json;
const execution = errorData.execution || {};
const workflow = errorData.workflow || {};

// Try to extract traceId from various sources
let traceId = null;
let sessionId = null;

// Check execution metadata
if (execution.metadata && execution.metadata.traceId) {
  traceId = execution.metadata.traceId;
}

// Check execution data for traceId
if (!traceId && execution.data) {
  const data = Array.isArray(execution.data) ? execution.data[0] : execution.data;
  if (data && data.json && data.json.traceId) {
    traceId = data.json.traceId;
    sessionId = data.json.sessionId;
  }
}

// Check workflow metadata
if (!traceId && workflow.metadata && workflow.metadata.traceId) {
  traceId = workflow.metadata.traceId;
}

// Extract error details
const errorMessage = execution.error?.message || execution.error?.name || 'Unknown error';
const errorStack = execution.error?.stack || '';
const lastNode = execution.lastNodeExecuted || 'Unknown node';
const executionId = execution.id || null;
const executionUrl = execution.url || null;

return [{
  json: {
    traceId,
    sessionId,
    errorMessage,
    errorStack,
    lastNode,
    executionId,
    executionUrl,
    workflowId: workflow.id || null,
    workflowName: workflow.name || 'Unknown workflow',
    mode: execution.mode || 'unknown'
  }
}];

parameters.jsonBody:
={{ JSON.stringify({
