  arguments: {
    traceId: $json.traceId,
    toAgent: 'error',
    instructions: `Workflow failed at node: ${$json.lastNode}. Error: ${$json.errorMessage}`,
    metadata: {
      executionId: $json.executionId,
      executionUrl: $json.executionUrl,
      workflowName: $json.workflowName,
      errorStack: $json.errorStack
    }
  }
}) }}

