// Log error for non-Telegram sessions or when Telegram notification fails
const errorData = $input.item.json;
console.log(JSON.stringify({
  event: 'workflow_error_handled',
  traceId: errorData.traceId,
  workflowName: errorData.workflowName,
  lastNode: errorData.lastNode,
  errorMessage: errorData.errorMessage,
  timestamp: new Date().toISOString()
}));

return $input.all();
